const token = process.env.GHL_PRIVATE_INTEGRATION_TOKEN;
const locationId = process.env.GHL_LOCATION_ID || 'TW8JsPW5NMnA3tfK2XLn';
const base = 'https://services.leadconnectorhq.com';
const headers = { Authorization: `Bearer ${token}`, Version: '2021-07-28', 'Content-Type': 'application/json' };

const now = Date.now();
const windowMs = 30 * 60 * 1000;
const since = now - windowMs;

const res = await fetch(`${base}/conversations/search?locationId=${locationId}&limit=100`, { headers });
if (!res.ok) throw new Error(`conversation search failed: ${res.status} ${await res.text()}`);
const data = await res.json();
const conversations = data.conversations || [];

const candidates = conversations.filter(c => (c.lastMessageDate || 0) >= since && String(c.lastMessageDirection||'').toLowerCase() === 'inbound');

const routineKeywords = /(password|forgot password|reset|login|log in|access|can'?t access|billing|charge|invoice|receipt|payment)/i;
const complexKeywords = /(refund|money back|chargeback|dispute|fraud|lawyer|legal|bbb|angry|frustrated|disappointed|complaint|cancel.*subscription|cancellation)/i;

const out = { nowIso: new Date(now).toISOString(), sinceIso: new Date(since).toISOString(), totalConversations: conversations.length, candidates: [] };

for (const c of candidates) {
  const mRes = await fetch(`${base}/conversations/${c.id}/messages?limit=20`, { headers });
  const mJson = await mRes.json();
  const msgs = mJson?.messages?.messages || [];
  const inbound = msgs.find(m => String(m.direction).toLowerCase() === 'inbound') || msgs[0];
  const body = inbound?.body || c.lastMessageBody || '';
  const isComplex = complexKeywords.test(body);
  const isRoutine = routineKeywords.test(body) && !isComplex;
  let category = 'other';
  if (isComplex) category = 'complex';
  else if (isRoutine) category = 'routine';

  let confidence = 0.55;
  if (category === 'complex') confidence = 0.95;
  if (category === 'routine') confidence = 0.92;

  out.candidates.push({
    conversationId: c.id,
    contactId: c.contactId,
    contactName: c.contactName || c.fullName,
    channelType: c.lastMessageType,
    unreadCount: c.unreadCount,
    lastMessageDate: new Date(c.lastMessageDate).toISOString(),
    snippet: String(body).slice(0,180),
    category,
    confidence,
    messagesChecked: msgs.length
  });
}

console.log(JSON.stringify(out, null, 2));

const BASE='https://services.leadconnectorhq.com';
const LOCATION=process.env.GHL_LOCATION_ID||'TW8JsPW5NMnA3tfK2XLn';
const TOKEN=process.env.GHL_PRIVATE_INTEGRATION_TOKEN;
const NOW=Date.now();
const WINDOW_MS=30*60*1000;
const headers={Authorization:`Bearer ${TOKEN}`,Version:'2021-07-28','Content-Type':'application/json'};

const req=async(method,path,body)=>{
  const r=await fetch(BASE+path,{method,headers,body:body?JSON.stringify(body):undefined});
  const t=await r.text();
  let j={}; try{j=t?JSON.parse(t):{}}catch{j={raw:t}};
  if(!r.ok) throw new Error(`${method} ${path} -> ${r.status} ${t.slice(0,300)}`);
  return j;
};

const classify=(text='')=>{
  const t=text.toLowerCase();
  const has=(arr)=>arr.some(k=>t.includes(k));
  if(has(['refund','money back','chargeback','dispute'])) return {category:'complex_refund',confidence:0.98};
  if(has(['angry','frustrated','disappointed','terrible','awful','scam','lawyer','legal','bbb','sue','complaint'])) return {category:'complex_complaint',confidence:0.95};
  if(has(['password','forgot password','reset password'])) return {category:'routine_password',confidence:0.95};
  if(has(['access','can\'t log in','cannot log in','login','member portal','course'])) return {category:'routine_access',confidence:0.9};
  if(has(['billing','invoice','receipt','payment','charged','charge'])) return {category:'routine_billing',confidence:0.9};
  return {category:'unknown',confidence:0.4};
};

const templates={
  routine_password:(name)=>`Hi ${name||'there'},\n\nHere\'s how to reset your password:\n1) Go to members.truthjblue.com/forgot-password\n2) Enter your email and submit\n3) Check your inbox (and spam folder) for the reset link\n\nIf you still can\'t access your account, reply here and I\'ll help you directly.`,
  routine_access:(name)=>`Hi ${name||'there'},\n\nYour course access steps:\n1) Log in at members.truthjblue.com\n2) Use the same email you purchased with\n3) Open your dashboard and start with Module 1\n\nIf the course still doesn\'t appear, reply with the purchase email and I\'ll fix it for you.`,
  routine_billing:(name)=>`Hi ${name||'there'},\n\nHappy to help with billing. I can confirm your purchase details and resend your receipt if needed.\n\nPlease share the email used at checkout and (if possible) the purchase date so I can locate it quickly.`
};

if(!TOKEN){
  console.log(JSON.stringify({error:'missing_GHL_PRIVATE_INTEGRATION_TOKEN'}));
  process.exit(0);
}

const out={processed:0,autoResponsesSent:0,escalations:0,items:[]};
const convRes=await req('GET',`/conversations/search?locationId=${LOCATION}&limit=100`);
const conversations=(convRes.conversations||[]).filter(c=>{
  const last=Number(c.lastMessageDate||0);
  const inbound=String(c.lastMessageDirection||'').toLowerCase()==='inbound';
  const unread=Number(c.unreadCount||0)>0;
  return inbound && unread && (NOW-last)<=WINDOW_MS && (NOW-last)>=0;
});

for(const c of conversations){
  const contactId=c.contactId;
  const contact=contactId?await req('GET',`/contacts/${contactId}`):{};
  const name=(contact.contact?.firstName||contact.contact?.name||c.contactName||c.fullName||'there');
  let latestInbound=(c.lastMessageBody||'').trim();
  try{
    const msgs=await req('GET',`/conversations/${c.id}/messages?limit=25`);
    const arr=msgs.messages||[];
    const inboundMsg=arr.find(m=>String(m.direction||'').toLowerCase()==='inbound' || String(m.messageDirection||'').toLowerCase()==='inbound');
    if(inboundMsg?.body||inboundMsg?.message) latestInbound=(inboundMsg.body||inboundMsg.message).trim();
  }catch{}

  const cls=classify(latestInbound);
  out.processed++;
  const record={conversationId:c.id,contactId,name,category:cls.category,confidence:cls.confidence,action:'none'};

  if(cls.category.startsWith('routine_')){
    const draft=templates[cls.category](name);
    record.draft=draft;
    // autosend only for high confidence and SMS/email capable types
    const convType=String(c.lastMessageType||c.type||'').toUpperCase();
    if(cls.confidence>=0.9 && contactId && (convType.includes('SMS')||convType.includes('PHONE')||convType.includes('EMAIL'))){
      try{
        const sendType=convType.includes('EMAIL')?'Email':'SMS';
        const body=sendType==='Email'
          ?{type:'Email',contactId,subject:'Support Follow-up',message:draft}
          :{type:'SMS',contactId,message:draft};
        await req('POST','/conversations/messages',body);
        out.autoResponsesSent++;
        record.action='auto_sent';
      }catch(err){
        record.action='draft_only_send_failed';
        record.error=String(err.message||err);
      }
    } else {
      record.action='draft_only';
    }
  } else if(cls.category.startsWith('complex_')){
    out.escalations++;
    record.action='escalate';
    record.draft=`Escalation draft for ${name}:\n\nThanks for reaching out — I\'m sorry you\'re dealing with this. I\'ve escalated your message to our support lead for priority review, and we\'ll follow up as soon as possible.`;
  } else {
    record.action='manual_review';
  }

  out.items.push(record);
}

console.log(JSON.stringify(out,null,2));
